.darma-loader-uiverse-button-save-dots {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 5px;
      min-width: 36px;
      min-height: 14px;
    }
    .darma-loader-uiverse-button-save-dots i {
      display: block;
      width: 7px;
      height: 7px;
      border-radius: 50%;
      background: var(--loader-color, #0ea5e9);
      animation: darma-loader-uiverse-button-save-dots-dotPulse 0.72s ease-in-out infinite;
    }
    .darma-loader-uiverse-button-save-dots i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-uiverse-button-save-dots i:nth-child(2) { animation-delay: 0.12s; }
.darma-loader-uiverse-button-save-dots i:nth-child(3) { animation-delay: 0.24s; }
    @keyframes darma-loader-uiverse-button-save-dots-dotPulse { 0%, 80%, 100% { transform: translateY(0) scale(.75); opacity: .45; } 40% { transform: translateY(-8px) scale(1); opacity: 1; } }

